export interface Vector2 {
  x: number;
  y: number;
}

export interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

export class InputManager {
  private keys: Set<string> = new Set();
  private touches: Map<number, Vector2> = new Map();

  constructor(canvas: HTMLCanvasElement) {
    window.addEventListener('keydown', (e) => {
      this.keys.add(e.code);
    });
    window.addEventListener('keyup', (e) => {
      this.keys.delete(e.code);
    });
    canvas.addEventListener('touchstart', (e) => {
      e.preventDefault();
      for (const t of Array.from(e.changedTouches)) {
        const r = canvas.getBoundingClientRect();
        this.touches.set(t.identifier, {
          x: t.clientX - r.left,
          y: t.clientY - r.top,
        });
      }
    });
    canvas.addEventListener('touchmove', (e) => {
      e.preventDefault();
      for (const t of Array.from(e.changedTouches)) {
        const r = canvas.getBoundingClientRect();
        this.touches.set(t.identifier, {
          x: t.clientX - r.left,
          y: t.clientY - r.top,
        });
      }
    });
    canvas.addEventListener('touchend', (e) => {
      for (const t of Array.from(e.changedTouches)) {
        this.touches.delete(t.identifier);
      }
    });
  }

  isKeyDown(code: string): boolean {
    return this.keys.has(code);
  }

  getTouches(): Vector2[] {
    return Array.from(this.touches.values());
  }
}

export class SpriteSheet {
  private image: HTMLImageElement;
  private frameWidth: number;
  private frameHeight: number;
  public loaded = false;

  constructor(src: string, frameWidth: number, frameHeight: number) {
    this.image = new Image();
    this.frameWidth = frameWidth;
    this.frameHeight = frameHeight;
    this.image.onload = () => { this.loaded = true; };
    this.image.src = src;
  }

  draw(ctx: CanvasRenderingContext2D, frameIndex: number, x: number, y: number, scale = 1) {
    if (!this.loaded) return;
    const cols = Math.floor(this.image.width / this.frameWidth);
    const sx = (frameIndex % cols) * this.frameWidth;
    const sy = Math.floor(frameIndex / cols) * this.frameHeight;
    ctx.drawImage(
      this.image, sx, sy, this.frameWidth, this.frameHeight,
      x, y, this.frameWidth * scale, this.frameHeight * scale
    );
  }
}

export abstract class Entity {
  public x = 0;
  public y = 0;
  public width = 0;
  public height = 0;
  public velocityX = 0;
  public velocityY = 0;
  public active = true;
  public tags: Set<string> = new Set();

  abstract update(dt: number, engine: GameEngine): void;
  abstract render(ctx: CanvasRenderingContext2D): void;

  getBounds(): Rect {
    return { x: this.x, y: this.y, width: this.width, height: this.height };
  }
}

export function checkCollision(a: Rect, b: Rect): boolean {
  return (
    a.x < b.x + b.width &&
    a.x + a.width > b.x &&
    a.y < b.y + b.height &&
    a.y + a.height > b.y
  );
}

export class GameEngine {
  public canvas: HTMLCanvasElement;
  public ctx: CanvasRenderingContext2D;
  public input: InputManager;
  public entities: Entity[] = [];
  public score = 0;
  public running = false;
  private lastTime = 0;
  private animFrameId = 0;
  private onScoreSubmit?: (score: number) => void;

  constructor(canvasId: string, onScoreSubmit?: (score: number) => void) {
    this.canvas = document.getElementById(canvasId) as HTMLCanvasElement;
    this.ctx = this.canvas.getContext('2d')!;
    this.input = new InputManager(this.canvas);
    this.onScoreSubmit = onScoreSubmit;
  }

  addEntity(entity: Entity) {
    this.entities.push(entity);
  }

  getEntitiesByTag(tag: string): Entity[] {
    return this.entities.filter((e) => e.active && e.tags.has(tag));
  }

  checkCollisions(entity: Entity, tag: string): Entity[] {
    const bounds = entity.getBounds();
    return this.getEntitiesByTag(tag).filter(
      (other) => other !== entity && checkCollision(bounds, other.getBounds())
    );
  }

  start() {
    this.running = true;
    this.lastTime = performance.now();
    this.loop(this.lastTime);
  }

  stop() {
    this.running = false;
    cancelAnimationFrame(this.animFrameId);
    if (this.onScoreSubmit) {
      this.onScoreSubmit(this.score);
    }
  }

  private loop = (now: number) => {
    if (!this.running) return;
    const dt = Math.min((now - this.lastTime) / 1000, 0.05);
    this.lastTime = now;

    this.update(dt);
    this.render();

    this.entities = this.entities.filter((e) => e.active);
    this.animFrameId = requestAnimationFrame(this.loop);
  };

  private update(dt: number) {
    for (const entity of this.entities) {
      if (entity.active) {
        entity.update(dt, this);
      }
    }
  }

  private render() {
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    for (const entity of this.entities) {
      if (entity.active) {
        entity.render(this.ctx);
      }
    }
  }
}

import { Entity, GameEngine, checkCollision } from './Engine';

class Player extends Entity {
  private speed = 300;
  private shootCooldown = 0;

  constructor(canvasWidth: number, canvasHeight: number) {
    super();
    this.width = 40;
    this.height = 40;
    this.x = canvasWidth / 2 - this.width / 2;
    this.y = canvasHeight - 60;
    this.tags.add('player');
  }

  update(dt: number, engine: GameEngine) {
    if (engine.input.isKeyDown('ArrowLeft') || engine.input.isKeyDown('KeyA')) {
      this.x -= this.speed * dt;
    }
    if (engine.input.isKeyDown('ArrowRight') || engine.input.isKeyDown('KeyD')) {
      this.x += this.speed * dt;
    }
    this.x = Math.max(0, Math.min(engine.canvas.width - this.width, this.x));

    // Touch input: move toward touch X position
    const touches = engine.input.getTouches();
    if (touches.length > 0) {
      const target = touches[0].x - this.width / 2;
      const diff = target - this.x;
      this.x += Math.sign(diff) * Math.min(Math.abs(diff), this.speed * dt);
    }

    this.shootCooldown -= dt;
    if (
      (engine.input.isKeyDown('Space') || touches.length > 0) &&
      this.shootCooldown <= 0
    ) {
      engine.addEntity(new Bullet(this.x + this.width / 2 - 2, this.y));
      this.shootCooldown = 0.2;
    }

    const hits = engine.checkCollisions(this, 'enemy');
    if (hits.length > 0) {
      engine.stop();
    }
  }

  render(ctx: CanvasRenderingContext2D) {
    ctx.fillStyle = '#00e5ff';
    ctx.beginPath();
    ctx.moveTo(this.x + this.width / 2, this.y);
    ctx.lineTo(this.x, this.y + this.height);
    ctx.lineTo(this.x + this.width, this.y + this.height);
    ctx.closePath();
    ctx.fill();
  }
}

class Bullet extends Entity {
  constructor(x: number, y: number) {
    super();
    this.x = x;
    this.y = y;
    this.width = 4;
    this.height = 12;
    this.velocityY = -500;
    this.tags.add('bullet');
  }

  update(dt: number, engine: GameEngine) {
    this.y += this.velocityY * dt;
    if (this.y + this.height < 0) {
      this.active = false;
      return;
    }
    const hits = engine.checkCollisions(this, 'enemy');
    if (hits.length > 0) {
      hits[0].active = false;
      this.active = false;
      engine.score += 100;
    }
  }

  render(ctx: CanvasRenderingContext2D) {
    ctx.fillStyle = '#ffeb3b';
    ctx.fillRect(this.x, this.y, this.width, this.height);
  }
}

class Enemy extends Entity {
  constructor(x: number, y: number) {
    super();
    this.x = x;
    this.y = y;
    this.width = 36;
    this.height = 36;
    this.velocityY = 80;
    this.tags.add('enemy');
  }

  update(dt: number, engine: GameEngine) {
    this.y += this.velocityY * dt;
    if (this.y > engine.canvas.height) {
      this.active = false;
    }
  }

  render(ctx: CanvasRenderingContext2D) {
    ctx.fillStyle = '#ff1744';
    ctx.fillRect(this.x, this.y, this.width, this.height);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(this.x + 8, this.y + 10, 6, 6);
    ctx.fillRect(this.x + 22, this.y + 10, 6, 6);
  }
}

class ScoreDisplay extends Entity {
  update(_dt: number, _engine: GameEngine) {}

  render(ctx: CanvasRenderingContext2D) {}
}

export function startSpaceShooter(
  canvasId: string,
  onScoreSubmit: (score: number) => void
) {
  const engine = new GameEngine(canvasId, onScoreSubmit);
  engine.addEntity(new Player(engine.canvas.width, engine.canvas.height));

  let spawnTimer = 0;
  const spawner = new (class extends Entity {
    update(dt: number, eng: GameEngine) {
      spawnTimer += dt;
      if (spawnTimer >= 1.0) {
        spawnTimer = 0;
        const x = Math.random() * (eng.canvas.width - 36);
        eng.addEntity(new Enemy(x, -40));
      }
    }
    render() {}
  })();

  const hud = new (class extends Entity {
    update() {}
    render(ctx: CanvasRenderingContext2D) {
      ctx.fillStyle = '#ffffff';
      ctx.font = '18px monospace';
      ctx.fillText(`Score: ${engine.score}`, 10, 28);
    }
  })();

  engine.addEntity(spawner);
  engine.addEntity(hud);
  engine.start();
  return engine;
}

export class Canvas2DRenderer {
  constructor(private ctx: CanvasRenderingContext2D) {}

  clear(color = '#1a1a2e') {
    this.ctx.fillStyle = color;
    this.ctx.fillRect(0, 0, this.ctx.canvas.width, this.ctx.canvas.height);
  }

  drawRect(x: number, y: number, w: number, h: number, color: string) {
    this.ctx.fillStyle = color;
    this.ctx.fillRect(x, y, w, h);
  }

  drawCircle(x: number, y: number, radius: number, color: string) {
    this.ctx.fillStyle = color;
    this.ctx.beginPath();
    this.ctx.arc(x, y, radius, 0, Math.PI * 2);
    this.ctx.fill();
  }

  drawText(text: string, x: number, y: number, opts: {
    color?: string; font?: string; align?: CanvasTextAlign;
  } = {}) {
    this.ctx.fillStyle = opts.color || '#fff';
    this.ctx.font = opts.font || '16px monospace';
    this.ctx.textAlign = opts.align || 'left';
    this.ctx.fillText(text, x, y);
  }

  drawImage(img: HTMLImageElement, sx: number, sy: number, sw: number, sh: number,
            dx: number, dy: number, dw: number, dh: number) {
    this.ctx.drawImage(img, sx, sy, sw, sh, dx, dy, dw, dh);
  }
}

const VERT_SRC = `
  attribute vec2 a_position;
  attribute vec2 a_texCoord;
  uniform vec2 u_resolution;
  varying vec2 v_texCoord;
  void main() {
    vec2 clip = (a_position / u_resolution) * 2.0 - 1.0;
    gl_Position = vec4(clip * vec2(1, -1), 0, 1);
    v_texCoord = a_texCoord;
  }
`;

const FRAG_SRC = `
  precision mediump float;
  varying vec2 v_texCoord;
  uniform sampler2D u_image;
  void main() {
    gl_FragColor = texture2D(u_image, v_texCoord);
  }
`;

export class WebGLRenderer {
  private gl: WebGLRenderingContext;
  private program: WebGLProgram;
  private posBuffer: WebGLBuffer;
  private texBuffer: WebGLBuffer;

  constructor(canvas: HTMLCanvasElement) {
    const gl = canvas.getContext('webgl')!;
    this.gl = gl;

    const vs = this.compileShader(gl.VERTEX_SHADER, VERT_SRC);
    const fs = this.compileShader(gl.FRAGMENT_SHADER, FRAG_SRC);
    this.program = gl.createProgram()!;
    gl.attachShader(this.program, vs);
    gl.attachShader(this.program, fs);
    gl.linkProgram(this.program);
    gl.useProgram(this.program);

    const resLoc = gl.getUniformLocation(this.program, 'u_resolution');
    gl.uniform2f(resLoc, canvas.width, canvas.height);

    this.posBuffer = gl.createBuffer()!;
    this.texBuffer = gl.createBuffer()!;

    gl.enable(gl.BLEND);
    gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
  }

  private compileShader(type: number, src: string): WebGLShader {
    const gl = this.gl;
    const shader = gl.createShader(type)!;
    gl.shaderSource(shader, src);
    gl.compileShader(shader);
    return shader;
  }

  loadTexture(image: HTMLImageElement): WebGLTexture {
    const gl = this.gl;
    const tex = gl.createTexture()!;
    gl.bindTexture(gl.TEXTURE_2D, tex);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, image);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    return tex;
  }

  drawSprite(tex: WebGLTexture, x: number, y: number, w: number, h: number) {
    const gl = this.gl;
    gl.bindTexture(gl.TEXTURE_2D, tex);

    const positions = new Float32Array([
      x, y, x + w, y, x, y + h,
      x, y + h, x + w, y, x + w, y + h,
    ]);
    const texCoords = new Float32Array([
      0, 0, 1, 0, 0, 1, 0, 1, 1, 0, 1, 1,
    ]);

    const posLoc = gl.getAttribLocation(this.program, 'a_position');
    gl.bindBuffer(gl.ARRAY_BUFFER, this.posBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, positions, gl.STATIC_DRAW);
    gl.enableVertexAttribArray(posLoc);
    gl.vertexAttribPointer(posLoc, 2, gl.FLOAT, false, 0, 0);

    const texLoc = gl.getAttribLocation(this.program, 'a_texCoord');
    gl.bindBuffer(gl.ARRAY_BUFFER, this.texBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, texCoords, gl.STATIC_DRAW);
    gl.enableVertexAttribArray(texLoc);
    gl.vertexAttribPointer(texLoc, 2, gl.FLOAT, false, 0, 0);

    gl.drawArrays(gl.TRIANGLES, 0, 6);
  }

  clear() {
    const gl = this.gl;
    gl.clearColor(0.1, 0.1, 0.18, 1);
    gl.clear(gl.COLOR_BUFFER_BIT);
  }
}

export interface GameState {
  gameId: string;
  score: number;
  level: number;
  checkpoint: string | null;
  inventory: Record<string, number>;
  playTime: number;
  savedAt: string;
}

const STORAGE_PREFIX = 'game_state_';

export class GameStateManager {
  private gameId: string;
  private state: GameState;

  constructor(gameId: string) {
    this.gameId = gameId;
    this.state = this.loadLocal() || {
      gameId,
      score: 0,
      level: 1,
      checkpoint: null,
      inventory: {},
      playTime: 0,
      savedAt: new Date().toISOString(),
    };
  }

  get current(): Readonly<GameState> {
    return this.state;
  }

  update(partial: Partial<GameState>) {
    Object.assign(this.state, partial, { savedAt: new Date().toISOString() });
    this.saveLocal();
  }

  private loadLocal(): GameState | null {
    try {
      const raw = localStorage.getItem(STORAGE_PREFIX + this.gameId);
      return raw ? JSON.parse(raw) : null;
    } catch {
      return null;
    }
  }

  private saveLocal() {
    localStorage.setItem(STORAGE_PREFIX + this.gameId, JSON.stringify(this.state));
  }

  async syncToServer(token: string): Promise<void> {
    await fetch('/api/game-state', {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify(this.state),
    });
  }

  async loadFromServer(token: string): Promise<void> {
    const res = await fetch(`/api/game-state/${this.gameId}`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (res.ok) {
      const serverState: GameState = await res.json();
      const localState = this.loadLocal();
      if (!localState || new Date(serverState.savedAt) > new Date(localState.savedAt)) {
        this.state = serverState;
        this.saveLocal();
      }
    }
  }

  reset() {
    localStorage.removeItem(STORAGE_PREFIX + this.gameId);
    this.state = {
      gameId: this.gameId, score: 0, level: 1,
      checkpoint: null, inventory: {}, playTime: 0,
      savedAt: new Date().toISOString(),
    };
  }
}

