export interface JoystickState {
  active: boolean;
  dx: number;  // -1 to 1 horizontal
  dy: number;  // -1 to 1 vertical
  angle: number;
  magnitude: number;
}

export class VirtualJoystick {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private centerX = 0;
  private centerY = 0;
  private knobX = 0;
  private knobY = 0;
  private radius = 50;
  private knobRadius = 20;
  private deadZone = 0.15;
  private touchId: number | null = null;
  public state: JoystickState = { active: false, dx: 0, dy: 0, angle: 0, magnitude: 0 };

  constructor(
    parentElement: HTMLElement,
    private position: { left: number; bottom: number },
    radius = 50
  ) {
    this.radius = radius;
    this.knobRadius = radius * 0.4;

    this.canvas = document.createElement('canvas');
    this.canvas.width = radius * 2 + 20;
    this.canvas.height = radius * 2 + 20;
    this.canvas.style.position = 'absolute';
    this.canvas.style.left = `${position.left}px`;
    this.canvas.style.bottom = `${position.bottom}px`;
    this.canvas.style.touchAction = 'none';
    this.canvas.style.zIndex = '1000';
    this.ctx = this.canvas.getContext('2d')!;

    this.centerX = this.canvas.width / 2;
    this.centerY = this.canvas.height / 2;
    this.knobX = this.centerX;
    this.knobY = this.centerY;

    parentElement.appendChild(this.canvas);

    this.canvas.addEventListener('touchstart', this.onTouchStart);
    this.canvas.addEventListener('touchmove', this.onTouchMove);
    this.canvas.addEventListener('touchend', this.onTouchEnd);

    this.draw();
  }

  private onTouchStart = (e: TouchEvent) => {
    e.preventDefault();
    if (this.touchId !== null) return;
    const touch = e.changedTouches[0];
    this.touchId = touch.identifier;
    this.updateKnob(touch);
  };

  private onTouchMove = (e: TouchEvent) => {
    e.preventDefault();
    for (const touch of Array.from(e.changedTouches)) {
      if (touch.identifier === this.touchId) {
        this.updateKnob(touch);
        break;
      }
    }
  };

  private onTouchEnd = (e: TouchEvent) => {
    for (const touch of Array.from(e.changedTouches)) {
      if (touch.identifier === this.touchId) {
        this.touchId = null;
        this.knobX = this.centerX;
        this.knobY = this.centerY;
        this.state = { active: false, dx: 0, dy: 0, angle: 0, magnitude: 0 };
        this.draw();
        break;
      }
    }
  };

  private updateKnob(touch: Touch) {
    const rect = this.canvas.getBoundingClientRect();
    let dx = touch.clientX - rect.left - this.centerX;
    let dy = touch.clientY - rect.top - this.centerY;
    const dist = Math.sqrt(dx * dx + dy * dy);

    if (dist > this.radius) {
      dx = (dx / dist) * this.radius;
      dy = (dy / dist) * this.radius;
    }

    this.knobX = this.centerX + dx;
    this.knobY = this.centerY + dy;

    const magnitude = Math.min(dist / this.radius, 1);
    const normalizedDx = dx / this.radius;
    const normalizedDy = dy / this.radius;

    if (magnitude < this.deadZone) {
      this.state = { active: true, dx: 0, dy: 0, angle: 0, magnitude: 0 };
    } else {
      this.state = {
        active: true,
        dx: normalizedDx,
        dy: normalizedDy,
        angle: Math.atan2(dy, dx),
        magnitude,
      };
    }
    this.draw();
  }

  private draw() {
    const ctx = this.ctx;
    ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

    // Base circle
    ctx.beginPath();
    ctx.arc(this.centerX, this.centerY, this.radius, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255, 255, 255, 0.15)';
    ctx.fill();
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Knob
    ctx.beginPath();
    ctx.arc(this.knobX, this.knobY, this.knobRadius, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
    ctx.fill();
  }

  destroy() {
    this.canvas.removeEventListener('touchstart', this.onTouchStart);
    this.canvas.removeEventListener('touchmove', this.onTouchMove);
    this.canvas.removeEventListener('touchend', this.onTouchEnd);
    this.canvas.remove();
  }
}

export function setupResponsiveCanvas(
  canvas: HTMLCanvasElement,
  designWidth: number,
  designHeight: number
): () => void {
  const dpr = window.devicePixelRatio || 1;

  function resize() {
    const parent = canvas.parentElement;
    if (!parent) return;

    const containerWidth = parent.clientWidth;
    const containerHeight = parent.clientHeight;
    const scale = Math.min(
      containerWidth / designWidth,
      containerHeight / designHeight
    );

    const displayWidth = Math.floor(designWidth * scale);
    const displayHeight = Math.floor(designHeight * scale);

    canvas.style.width = `${displayWidth}px`;
    canvas.style.height = `${displayHeight}px`;
    canvas.width = displayWidth * dpr;
    canvas.height = displayHeight * dpr;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.scale(dpr, dpr);
    }
  }

  resize();
  window.addEventListener('resize', resize);

  return () => window.removeEventListener('resize', resize);
}

export function requestOrientationLock(orientation: 'landscape' | 'portrait') {
  const screenAny = screen as any;
  if (screenAny.orientation && screenAny.orientation.lock) {
    screenAny.orientation.lock(orientation).catch(() => {
      // Orientation lock not supported or not in fullscreen
    });
  }
}

export function enterFullscreen(element: HTMLElement) {
  const el = element as any;
  const requestFs = el.requestFullscreen
    || el.webkitRequestFullscreen
    || el.mozRequestFullScreen
    || el.msRequestFullscreen;
  if (requestFs) {
    requestFs.call(el);
  }
}

import hmac
import hashlib
import time
import os

SECRET = os.getenv('ANTICHEAT_SECRET', 'change-me-in-production')

def create_session_token(user_id: int, game_id: int) -> dict:
    """Issue a signed session token when the game starts."""
    start_time = int(time.time())
    payload = f"{user_id}:{game_id}:{start_time}"
    signature = hmac.new(
        SECRET.encode(), payload.encode(), hashlib.sha256
    ).hexdigest()
    return {
        'token': f"{payload}:{signature}",
        'started_at': start_time,
    }

def verify_session_token(token: str, user_id: int, game_id: int) -> dict | None:
    """Verify the session token and return session metadata."""
    parts = token.rsplit(':', 1)
    if len(parts) != 2:
        return None
    payload, signature = parts
    expected = hmac.new(
        SECRET.encode(), payload.encode(), hashlib.sha256
    ).hexdigest()
    if not hmac.compare_digest(signature, expected):
        return None

    fields = payload.split(':')
    if len(fields) != 3:
        return None
    tok_user, tok_game, tok_start = fields
    if int(tok_user) != user_id or int(tok_game) != game_id:
        return None

    start_time = int(tok_start)
    elapsed = int(time.time()) - start_time
    return {
        'start_time': start_time,
        'elapsed_seconds': elapsed,
    }

def validate_score(
    score: int,
    elapsed_seconds: int,
    max_score_per_second: int = 500,
    min_session_seconds: int = 5
) -> tuple[bool, str]:
    """Check if a score is plausible given the session duration."""
    if elapsed_seconds < min_session_seconds:
        return False, 'Session too short'
    if score < 0:
        return False, 'Negative score'
    rate = score / max(elapsed_seconds, 1)
    if rate > max_score_per_second:
        return False, f'Score rate {rate:.0f}/s exceeds max {max_score_per_second}/s'
    return True, 'ok'

